values ('the-last-goodbye', 'the-last-goodbye-i-never-got', 'The Last Goodbye I Never Got', 'A Story of Love, Loss, and the Echoes We Carry', 'Some goodbyes are spoken. Others arrive without warning. And some remain unfinished forever.', 'The Last Goodbye I Never Got is Anurag Verma''s autobiographical coming-of-age novel, tracing his journey from a quiet childhood in Sikanderpur through love, heartbreak, family, friendship, dreams, grief, and responsibility.', 'An autobiographical coming-of-age novel about love, loss, resilience, and the unfinished goodbyes that shape us.', '["Autobiographical Novel","Literary Fiction","Coming-of-Age","Memoir"]'::jsonb, '["Love","Loss","Family","Friendship","Grief","Hope","Resilience","Self-discovery"]'::jsonb, 'published', '2026-02-14', 264, 'English & Hindi', '978-93-91377-01-1', 'Independent / Author Edition', '{"paperback":true,"ebook":true}'::jsonb, '{"paperback":"https://amazon.in/stores/Anurag-Verma/author/B0H7PH8QW4","ebook":"https://amazon.in/stores/Anurag-Verma/author/B0H7PH8QW4","amazon":"https://amazon.in/stores/Anurag-Verma/author/B0H7PH8QW4","goodreads":"https://goodreads.com/anuragvrm2173"}'::jsonb, 'lastGoodbye-en', '["the-untold-stories","lessons-of-the-heart"]'::jsonb, '["the-story-behind-the-words","why-i-wrote-the-last-goodbye"]'::jsonb, '{"title":"The Last Goodbye I Never Got | Anurag Verma","description":"Explore The Last Goodbye I Never Got by Anurag Verma, an autobiographical novel on love, loss, and emotional resilience."}'::jsonb, '["The Last Goodbye I Never Got follows a deeply personal journey through childhood memories, first love, heartbreak, family expectations, and the ache of unfinished conversations.","It is more than a love story. It is a human story about growing up, carrying grief with grace, and discovering that resilience is often born in silence."]'::jsonb, '["How unfinished goodbyes remain with us and still teach us how to live.","The emotional threads connecting love, family, friendship, and identity.","Why healing often begins when we stop hiding from memory."]'::jsonb, '["Readers of deeply personal literary fiction and memoir-inspired storytelling.","Anyone navigating grief, heartbreak, or unfinished emotional conversations.","Readers looking for emotionally honest stories about healing and resilience."]'::jsonb, '6-7 hours', '["Some goodbyes never happen in words, only in silence.","Love does not end when a chapter closes.","We heal when we stop running from memory."]'::jsonb, '{"english":{"label":"English","languageCode":"en","available":true,"formatLabel":"English Edition","pricing":{"paperback":{"currency":"INR","amount":419}},"isbn":"978-93-91377-01-1","publicationDate":"2026-06-10","pages":198,"publisher":"Pothi.com","formats":{"paperback":true,"ebook":true},"cover":{"eyebrow":"Published","author":"Anurag Verma","subtitle":"(English Edition)","frontCover":null,"fullCover":null},"sampleId":"lastGoodbye-en","readingTime":"6-7 hours","favoriteQuotes":["Some goodbyes never happen in words, only in silence.","Love does not end when a chapter closes.","We heal when we stop running from memory."],"purchaseLinks":{"paperback":"https://amazon.in/stores/Anurag-Verma/author/B0H7PH8QW4","kindle":"https://amazon.in/stores/Anurag-Verma/author/B0H7PH8QW4","amazon":"https://amazon.in/stores/Anurag-Verma/author/B0H7PH8QW4","pothi":"https://store.pothi.com/book/anurag-verma-last-goodbye-i-never-got/"}},"hindi":{"label":"हिन्दी","languageCode":"hi","available":true,"formatLabel":"हिन्दी संस्करण","pricing":{"currency":"INR","amount":399},"isbn":"979-8905607691","asin":"B0H7X86J4G","publicationDate":"2026-07-06","pages":262,"publisher":"Notion Press","country":"India","weight":"168 g","dimensions":"22.86 x 15.24 x 1.3 cm","formats":{"paperback":true,"ebook":true},"language":"Hindi","cover":{"eyebrow":"Published","author":"अनुराग वर्मा","subtitle":"(Hindi Edition)","frontCover":null,"fullCover":null},"sampleId":"lastGoodbye-hi","readingTime":"6-7 hours","favoriteQuotes":["कुछ अलविदा शब्दों में नहीं, खामोशी में होते हैं।","प्रेम अध्याय खत्म होने से खत्म नहीं होता।","यादों से भागना छोड़ दें तो उपचार शुरू होता है।"],"retailers":{"amazon":{"name":"Amazon","available":true,"label":"Buy from Amazon","url":"https://amzn.in/d/01fjGfzJ"},"notionPress":{"name":"Notion Press","available":true,"label":"Buy from Notion Press","url":"https://notionpress.com/read/the-last-goodbye-i-never-got"},"flipkart":{"name":"Flipkart","available":false,"label":"Coming Soon"}},"metadata":{"publisher":"Notion Press","publicationDate":"2026-07-06","language":"Hindi","pages":262,"isbn13":"979-8905607691","asin":"B0H7X86J4G","weight":"168 g","dimensions":"22.86 x 15.24 x 1.3 cm","country":"India","genericName":"Books"},"packer":{"name":"Notion Press Media Pvt Ltd","address":["No. 50,","Chettiyar Agaram Main Road,","Vanagaram,","Chennai - 600095"],"website":"https://notionpress.com/store","email":"orders@notionpress.com"}}}'::jsonb, '2026-07-08T09:00:56.501Z')
