values ('the-untold-stories', 'the-untold-stories', 'The Untold Stories Behind The Last Goodbye I Never Got', 'The Stories Between the Chapters', 'Every story leaves behind moments that never make it into the final manuscript.', 'This companion book revisits The Last Goodbye I Never Got, revealing the memories, conversations, and reflections that lived between its pages.', 'A companion memoir that expands the emotional world behind The Last Goodbye I Never Got.', '["Companion Memoir","Personal Reflections","Literary Nonfiction"]'::jsonb, '["Reflection","Memory","Relationships","Personal Growth","Behind the Story","Healing"]'::jsonb, 'coming_soon', null, null, 'English & Hindi', null, null, '{"paperback":true,"ebook":true}'::jsonb, '{}'::jsonb, 'untold-en', '["the-last-goodbye","lessons-of-the-heart"]'::jsonb, '["the-story-behind-the-words","behind-the-book-untold-stories"]'::jsonb, '{"title":"The Untold Stories Behind The Last Goodbye I Never Got | Anurag Verma","description":"Discover the companion memoir from Anurag Verma that reveals the untold chapters behind The Last Goodbye I Never Got."}'::jsonb, '["Rather than continuing the original story, this book expands it through unseen moments, personal reflections, and emotional context that stayed between the lines.","It offers readers a deeper understanding of the people, choices, and memories that quietly shaped the journey."]'::jsonb, '["The conversations and silences that remained outside the first manuscript.","How memory reshapes the meaning of earlier chapters.","Why untold stories can become the most transformative ones."]'::jsonb, '["Readers who loved The Last Goodbye I Never Got and want deeper context.","Anyone curious about untold chapters, emotional backstory, and reflection.","Readers who appreciate intimate nonfiction and companion memoirs."]'::jsonb, '5-6 hours', '["Untold stories are often the ones that changed us most.","Memory edits nothing; it reveals what mattered.","What we could not publish still shaped every page."]'::jsonb, '{"english":{"label":"English","languageCode":"en","available":true,"formatLabel":"English Edition","isbn":null,"isbn13":null,"asin":null,"publicationDate":null,"pages":null,"publisher":null,"weight":null,"dimensions":null,"country":null,"formats":{"paperback":true,"ebook":true},"cover":{"eyebrow":"Coming Soon","author":"Anurag Verma","subtitle":"(English Edition)","frontCover":null,"fullCover":null},"sampleId":"untold-en","readingTime":"5-6 hours","favoriteQuotes":["Untold stories are often the ones that changed us most.","Memory edits nothing; it reveals what mattered.","What we could not publish still shaped every page."],"metadata":{"publisher":null,"publicationDate":null,"language":"English","pages":null,"isbn13":null,"asin":null,"weight":null,"dimensions":null,"country":null,"genericName":null},"packer":null,"purchaseLinks":{}},"hindi":{"label":"हिन्दी","languageCode":"hi","available":true,"formatLabel":"Hindi Edition","isbn":null,"isbn13":null,"asin":null,"publicationDate":null,"pages":null,"publisher":null,"weight":null,"dimensions":null,"country":null,"formats":{"paperback":true,"ebook":true},"cover":{"eyebrow":"Coming Soon","author":"अनुराग वर्मा","subtitle":"(Hindi Edition)","frontCover":null,"fullCover":null},"sampleId":"untold-hi","readingTime":"5-6 hours","favoriteQuotes":["अनकही कहानियां अक्सर वही होती हैं जो हमें बदल देती हैं।","स्मृति कुछ नहीं छिपाती, वही दिखाती है जो महत्वपूर्ण था।","जो छपा नहीं, उसने भी पूरी किताब को आकार दिया।"],"metadata":{"publisher":null,"publicationDate":null,"language":"Hindi","pages":null,"isbn13":null,"asin":null,"weight":null,"dimensions":null,"country":null,"genericName":null},"packer":null,"purchaseLinks":{}}}'::jsonb, '2026-07-08T09:00:56.501Z')
