values ('lessons-of-the-heart', 'lessons-of-the-heart', 'Lessons of the Heart', 'Love, Loss, Life, and the Wisdom Behind The Last Goodbye I Never Got', 'The lessons that shape us most are rarely learned through success. They are learned through love, loss, and the people we never forget.', 'Lessons of the Heart transforms lived experiences into reflections on healing, forgiveness, purpose, friendship, and hope.', 'An inspirational nonfiction work on healing, purpose, and life lessons born from lived experience.', '["Inspirational Nonfiction","Personal Growth","Philosophy","Self-Reflection"]'::jsonb, '["Healing","Wisdom","Love","Purpose","Hope","Forgiveness","Resilience","Life Lessons"]'::jsonb, 'coming_soon', null, null, 'English & Hindi', null, null, '{"paperback":true,"ebook":true}'::jsonb, '{}'::jsonb, 'lessons-en', '["the-last-goodbye","the-untold-stories"]'::jsonb, '["the-story-behind-the-words","difference-between-healing-and-moving-on","what-readers-carry-from-stories"]'::jsonb, '{"title":"Lessons of the Heart | Anurag Verma","description":"Read about Lessons of the Heart, an upcoming inspirational nonfiction title by Anurag Verma on healing, hope, and purpose."}'::jsonb, '["Drawing from the emotional foundations of earlier work, this book turns memory into practical wisdom for everyday life.","It is a collection of reflections reminding readers that every goodbye, every mistake, and every beginning carries a lesson."]'::jsonb, '["How difficult seasons can reveal purpose instead of only pain.","Why forgiveness and self-compassion are forms of strength.","How hope can be practiced in ordinary moments."]'::jsonb, '["Readers seeking practical emotional wisdom from lived experience.","Anyone working through healing, purpose, and personal growth.","Readers who enjoy reflective nonfiction and life lessons they can apply daily."]'::jsonb, '4-5 hours', '["A broken heart can still become a wise one.","Healing is not forgetting; it is understanding.","Hope is a daily practice, not a single moment."]'::jsonb, '{"english":{"label":"English","languageCode":"en","available":true,"formatLabel":"English Edition","isbn":null,"isbn13":null,"asin":null,"publicationDate":null,"pages":null,"publisher":null,"weight":null,"dimensions":null,"country":null,"formats":{"paperback":true,"ebook":true},"cover":{"eyebrow":"Coming Soon","author":"Anurag Verma","subtitle":"(English Edition)","frontCover":null,"fullCover":null},"sampleId":"lessons-en","readingTime":"4-5 hours","favoriteQuotes":["A broken heart can still become a wise one.","Healing is not forgetting; it is understanding.","Hope is a daily practice, not a single moment."],"metadata":{"publisher":null,"publicationDate":null,"language":"English","pages":null,"isbn13":null,"asin":null,"weight":null,"dimensions":null,"country":null,"genericName":null},"packer":null,"purchaseLinks":{}},"hindi":{"label":"हिन्दी","languageCode":"hi","available":true,"formatLabel":"Hindi Edition","isbn":null,"isbn13":null,"asin":null,"publicationDate":null,"pages":null,"publisher":null,"weight":null,"dimensions":null,"country":null,"formats":{"paperback":true,"ebook":true},"cover":{"eyebrow":"Coming Soon","author":"अनुराग वर्मा","subtitle":"(Hindi Edition)","frontCover":null,"fullCover":null},"sampleId":"lessons-hi","readingTime":"4-5 hours","favoriteQuotes":["टूटा हुआ दिल भी समझदार बन सकता है।","उपचार भूलना नहीं, समझना है।","आशा एक अभ्यास है, एक पल नहीं।"],"metadata":{"publisher":null,"publicationDate":null,"language":"Hindi","pages":null,"isbn13":null,"asin":null,"weight":null,"dimensions":null,"country":null,"genericName":null},"packer":null,"purchaseLinks":{}}}'::jsonb, '2026-07-08T09:00:56.501Z')
