insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('the-story-behind-the-words', 'the-story-behind-the-words', 'The Story Behind the Words', 'Every book begins long before the first sentence. These are the moments, losses, and lessons that became the foundation of Anurag Verma''s work.', '8 min read', 'July 2026', 'Author Journey', false, '["the-last-goodbye","the-untold-stories","lessons-of-the-heart"]'::jsonb, '{"motif":"Every book begins before the first sentence."}'::jsonb, '[]'::jsonb, '[{"heading":"Who I Am","paragraphs":["I''m Anurag Verma, an Indian author who believes that stories have the power to stay with us long after we''ve finished reading them.","I don''t write to escape life. I write to understand it. The moments that shaped me, the people I loved, the losses I carried, and the lessons I learned have all found their way into my work.","My books are deeply personal, but they are also about the emotions we all experience: love, grief, hope, regret, healing, and the quiet courage it takes to keep moving forward.","If my words help even one reader feel understood, then they have done what they were meant to do."]},{"heading":"Why I Write","paragraphs":["Writing began as a way of making sense of experiences I could not explain.","Some stories are too important to remain memories. They deserve to become words, because somewhere, someone else may be living through the same chapter.","I don''t write to offer perfect advice or easy answers. I write because stories have a unique way of reaching places that advice never can.","If a reader closes one of my books feeling a little less alone, a little more hopeful, or simply understood, then every page has served its purpose."]},{"heading":"The Books","paragraphs":["Every book I write builds upon the one before it.","The Last Goodbye I Never Got is where the journey begins, a deeply personal story of love, loss, and the echoes that remain long after goodbye.","The Untold Stories Behind The Last Goodbye I Never Got goes beyond the pages of that first book, revealing the experiences, emotions, and reflections that shaped its creation.","With Lessons of the Heart, those experiences grow into something larger: a collection of reflections on love, healing, resilience, and the quiet wisdom that often emerges only after life changes us.","Together, these books form a continuing journey, not separate stories, but different chapters of the same conversation."]},{"heading":"A Few Chapters of My Journey","paragraphs":["2026: Published my debut book, The Last Goodbye I Never Got, transforming deeply personal experiences into a story shared with readers.","Later in 2026: Released The Untold Stories Behind The Last Goodbye I Never Got, offering a closer look at the memories, emotions, and creative journey behind the first book.","Today: Continuing to write stories that explore love, loss, healing, and the lessons that shape us, while building a body of work that grows with every new book."]},{"heading":"What''s Next","paragraphs":["I''m still writing.","Not because every story has been told, but because every new season of life reveals something worth understanding.","The books ahead will continue exploring the emotions that connect us all: love, loss, resilience, hope, and the quiet moments that often change us the most.","My hope is simple: to create stories that readers return to, recommend to others, and carry with them long after the final page.","Because sometimes a book does not change your life all at once. Sometimes, it simply stays with you until you''re ready to change your own."]}]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
