insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('why-i-wrote-the-last-goodbye', 'why-i-wrote-the-last-goodbye', 'Why I Wrote The Last Goodbye I Never Got', 'Some memories refuse to stay silent. Writing became the only way to preserve moments that shaped me before time softened their edges.', '7 min read', 'July 2026', 'Behind the Book', false, '[]'::jsonb, '{}'::jsonb, '["People often ask why I decided to write such a personal story. The answer is simple: some memories refuse to stay silent.","For years, I carried moments I could not fully explain: love that changed me, loss that stayed with me, and conversations I replayed in my mind long after they were over.","Writing became the only way to preserve those experiences before time softened their edges.","I did not write this book because I had all the answers. I wrote it because I was still searching for them.","If someone finds a piece of their own story inside mine, then every page was worth writing."]'::jsonb, '[]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
