insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('how-personal-loss-changed-my-writing', 'how-personal-loss-changed-my-writing', 'How Personal Loss Changed My Writing', 'Loss changed what I notice and what I choose to write. The smallest moments began to carry the deepest meaning.', '6 min read', 'June 2026', 'Writing', false, '[]'::jsonb, '{}'::jsonb, '["Loss changes more than our lives. It changes the way we see people, the way we remember moments, and the way we tell stories.","Before loss, I focused on events. After loss, I began noticing emotions hidden inside ordinary moments.","A conversation with my father. A quiet sacrifice by my mother. A message from someone I loved.","Those experiences taught me that the smallest moments often become the ones we carry forever.","That realization changed not only what I write, but why I write."]'::jsonb, '[]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
