insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('why-stories-matter-more-than-advice', 'why-stories-matter-more-than-advice', 'Why Stories Matter More Than Advice', 'Advice tells people what to do. Stories allow people to discover meaning in their own way.', '5 min read', 'May 2026', 'Storytelling', false, '[]'::jsonb, '{}'::jsonb, '["Advice tells people what to do. Stories allow people to discover it for themselves.","A lesson can be forgotten, but a story has a way of staying with us.","Long after we finish a book, we remember a character, a conversation, or a single moment that changes how we see our own lives.","That is why I choose stories over instructions.","I do not want to tell readers what to think. I want to share honestly and let them find the meaning that speaks to them."]'::jsonb, '[]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
