insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('difference-between-healing-and-moving-on', 'difference-between-healing-and-moving-on', 'The Difference Between Healing and Moving On', 'Moving on and healing are not the same. Healing is learning to carry memory without letting it define your life.', '5 min read', 'April 2026', 'Healing', false, '[]'::jsonb, '{}'::jsonb, '["People often use healing and moving on as if they mean the same thing. I do not believe they do.","Moving on suggests leaving something behind. Healing is learning how to carry it without letting it define every part of your life.","Some people will always remain part of your story. Some losses never disappear completely.","Healing does not erase memories. It changes the relationship you have with them.","For me, writing has never been about forgetting. It has always been about understanding."]'::jsonb, '[]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
