insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('behind-the-book-untold-stories', 'behind-the-book-untold-stories', 'Behind the Book: The Untold Stories', 'Every book leaves something behind. This companion work explores the moments that lived between published chapters.', '6 min read', 'March 2026', 'Behind the Book', false, '[]'::jsonb, '{}'::jsonb, '["Every book leaves something behind. Not because those moments are unimportant, but because not every memory belongs in the main story.","The Untold Stories grew from pages that did not make it into the first book.","It is not a sequel. It is a deeper look at the people, moments, and emotions that shaped the journey.","It offers readers a chance to see the same story from another perspective.","Sometimes what remains untold is just as meaningful as what is written."]'::jsonb, '[]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
