insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('what-readers-carry-from-stories', 'what-readers-carry-from-stories', 'What Readers Carry from Stories', 'The best books do not just end. They continue quietly in how readers think, remember, and heal.', '6 min read', 'February 2026', 'Reflection', false, '[]'::jsonb, '{}'::jsonb, '["A story lives twice: once in writing and once in the reader who receives it.","Readers often remember one line, one chapter, one character that met them at the right time.","Those fragments become emotional tools they return to during difficult days.","That is the quiet power of literature. It does not always solve pain, but it gives shape to it.","When a reader says, ''I felt seen,'' that is the deepest form of success for any writer."]'::jsonb, '[]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
