insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('writing-with-emotional-honesty', 'writing-with-emotional-honesty', 'Writing with Emotional Honesty', 'Emotional honesty is not dramatic writing. It is precise writing that stays truthful to lived experience.', '5 min read', 'January 2026', 'Writing', false, '[]'::jsonb, '{}'::jsonb, '["Emotional honesty begins with attention. Noticing what was actually felt, not just what sounds poetic.","It asks a writer to resist exaggeration and stay near truth.","In personal writing, honesty does not mean sharing everything. It means sharing the right things clearly.","Readers can recognize sincerity quickly. They can also recognize performance.","When language is honest, it creates trust. Trust is what turns pages into connection."]'::jsonb, '[]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
