insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('family-memory-and-language', 'family-memory-and-language', 'Family, Memory, and the Language of Home', 'The emotional vocabulary we inherit from family shapes how we remember, grieve, and heal.', '4 min read', 'December 2025', 'Personal', false, '[]'::jsonb, '{}'::jsonb, '["Before we learn literary language, we learn emotional language at home.","How families speak about love, conflict, sacrifice, and silence becomes part of our voice.","When I write about family, I am writing about the first place where I learned both tenderness and resilience.","Memory does not preserve facts alone. It preserves tone, pauses, and the emotional weather of a room.","Those details are often where the truest stories live."]'::jsonb, '[]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
