insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('from-draft-to-book', 'from-draft-to-book', 'From Draft to Book: What Changes Most', 'The biggest change between draft and publication is usually clarity: what the story is truly trying to say.', '7 min read', 'November 2025', 'Process', false, '[]'::jsonb, '{}'::jsonb, '["Early drafts are full of urgency. Later drafts are full of decisions.","What to keep, what to cut, and what belongs in a different book entirely.","Revision is where a manuscript learns discipline. It is also where it discovers voice.","Publication is not the end of writing. It is the beginning of dialogue with readers.","A finished book is not perfect memory. It is the truest version we can offer at that time."]'::jsonb, '[]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
