insert into public.blog_posts (id, slug, title, excerpt, reading_time, published_at, category, featured, related_book_ids, visual, content, content_sections, seo_title, seo_description, updated_at)
values ('why-books-still-matter', 'why-books-still-matter', 'Why Books Still Matter in a Fast World', 'Books create the rarest modern experience: sustained attention to another human life.', '5 min read', 'October 2025', 'Reflection', false, '[]'::jsonb, '{}'::jsonb, '["A fast world rewards quick answers. Books reward careful understanding.","Reading asks us to slow down long enough to encounter complexity.","That matters especially in emotional life, where simple answers often fail.","Books give language to feelings we struggle to name.","In that sense, reading is not escape. It is practice for being fully human."]'::jsonb, '[]'::jsonb, null, null, '2026-07-08T09:00:56.504Z')
